%% P2_Exp09_regression_head_summary_plots.m
% Purpose:
% This script summarizes and visualizes regression-head comparison results
% for target-domain pack-level SOH prediction. It reads the prediction
% results generated by P2_Exp06, compares MLP, Gaussian process regression,
% and support vector regression heads, and generates summary plots for the
% associated Supplementary figure.

clc; clear; close all;

%% 1) Configuration
cfg = struct();

script_dir = fileparts(mfilename('fullpath'));
if isempty(script_dir)
    script_dir = pwd;
end

part_dir = script_dir;

cfg.output_results_dir = fullfile(part_dir, 'Output', 'Results');
cfg.figure_dir = fullfile(part_dir, 'Figures', 'Supplementary');

% Input file generated by P2_Exp06.
cfg.input_csv = fullfile(cfg.output_results_dir, ...
'P2_Exp06_RegressionHead_PackPredictions.csv');

% Output summary tables generated by P2_Exp09.
cfg.metrics_csv = fullfile(cfg.output_results_dir, 'P2_Exp09_RegressionHeadSummary_Metrics.csv');
cfg.pred_csv = fullfile(cfg.output_results_dir, 'P2_Exp09_RegressionHeadSummary_Predictions.csv');

% Output figures associated with Supplementary Fig. 4a-c.
cfg.fig_parity = fullfile(cfg.figure_dir, ...
    'SupFig04a_regression_head_parity_plot.fig');
cfg.png_parity = fullfile(cfg.figure_dir, ...
    'SupFig04a_regression_head_parity_plot.png');

cfg.fig_lollipop = fullfile(cfg.figure_dir, ...
    'SupFig04c_regression_head_RMSE_MAPE_lollipop.fig');
cfg.png_lollipop = fullfile(cfg.figure_dir, ...
    'SupFig04c_regression_head_RMSE_MAPE_lollipop.png');

cfg.fig_r2_gradient = fullfile(cfg.figure_dir, ...
    'SupFig04b_regression_head_R2_gradient.fig');
cfg.png_r2_gradient = fullfile(cfg.figure_dir, ...
    'SupFig04b_regression_head_R2_gradient.png');

cfg.png_resolution = 600;

if ~exist(cfg.output_results_dir, 'dir')
    mkdir(cfg.output_results_dir);
end

if ~exist(cfg.figure_dir, 'dir')
    mkdir(cfg.figure_dir);
end

fprintf('================ P2 Exp09: Regression-head summary plots ================\n');
fprintf('Input prediction file: %s\n', cfg.input_csv);


%% 2) Load data and calculate prediction metrics
if ~isfile(cfg.input_csv)
    error('Input file not found: %s. Please run P2_Exp06_regression_head_comparison.m first.', cfg.input_csv);
end

data = readtable(cfg.input_csv, 'VariableNamingRule', 'preserve');

y_true = local_get_numeric_col(data, {'True_SOH', 'True_Pack_SOH'});
y_mlp  = local_get_numeric_col(data, {'Pred_MLP', 'MLP'});
y_gpr  = local_get_numeric_col(data, {'Pred_GPR', 'GPR'});
y_svm  = local_get_numeric_col(data, {'Pred_SVM', 'SVM'});

pack_idx = local_get_optional_numeric_col(data, ...
    {'Pack_Index', 'Sample_Index', 'Index'}, ...
    (1:numel(y_true))');

pack_id = local_get_optional_text_col(data, ...
    {'Pack_ID', 'SN', 'SN_List'}, ...
    strings(numel(y_true), 1));

model_names = {'MLP', 'GPR', 'SVM'};
models = {y_mlp, y_gpr, y_svm};
num_models = length(models);

r2_vec = zeros(num_models, 1);
rmse_vec = zeros(num_models, 1);
mape_vec = zeros(num_models, 1);

y_mean = mean(y_true);

for i = 1:num_models
    err = models{i} - y_true;
    r2_vec(i) = 1 - (sum(err.^2) / sum((y_true - y_mean).^2));
    rmse_vec(i) = sqrt(mean(err.^2));
    mape_vec(i) = mean(abs(err ./ y_true));
end

colors = { ...
    [0.4660, 0.6740, 0.1880], ...  % MLP
    [0.0000, 0.4470, 0.7410], ...  % GPR
    [0.8500, 0.3250, 0.0980]};     % SVM

fprintf('\n========== Regression-head metrics ==========\n');

for i = 1:num_models
    fprintf('%-5s | R2 = %.4f | RMSE = %.4f | MAPE = %.4f\n', ...
        model_names{i}, r2_vec(i), rmse_vec(i), mape_vec(i));
end

%% 3) Panel F: Parity scatter plot
fig_parity = figure('Color', 'w', ...
    'Position', [100 100 550 550], ...
    'Name', 'P2_Exp09_RegressionHeadParity');

hold on;
grid on;
box on;

plot([0, 2], [0, 2], 'k--', ...
    'LineWidth', 1.5, ...
    'HandleVisibility', 'off');

alphas = [0.5, 0.6, 0.8];
markers = {'s', '^', 'p'};

for i = 1:num_models
    scatter(y_true, models{i}, 80, colors{i}, 'filled', ...
        'MarkerFaceAlpha', alphas(i), ...
        'MarkerEdgeColor', 'k', ...
        'Marker', markers{i}, ...
        'DisplayName', model_names{i});
end

xlim([0.84, 1.015]);
ylim([0.84, 1.015]);

xlabel('True SOH', ...
    'FontSize', 14, ...
    'FontWeight', 'bold');

ylabel('Predicted SOH', ...
    'FontSize', 14, ...
    'FontWeight', 'bold');

set(gca, ...
    'FontSize', 12, ...
    'FontName', 'Times New Roman');

legend('Location', 'northwest');

local_save_figure(fig_parity, ...
    cfg.fig_parity, ...
    cfg.png_parity, ...
    cfg.png_resolution);

%% 4) Panel G: Grouped horizontal lollipop chart for RMSE and MAPE
fig_lollipop = figure('Color', 'w', ...
    'Position', [150 150 700 500], ...
    'Name', 'P2_Exp09_RegressionHeadRMSESummary');

hold on;
grid on;

[~, sIdx] = sort(rmse_vec, 'ascend');

s_names = model_names(sIdx);
s_rmse  = rmse_vec(sIdx);
s_mape  = mape_vec(sIdx);

offset = 0.15;

for i = 1:num_models

    % RMSE.
    line([0, s_rmse(i)], [i + offset, i + offset], ...
        'Color', [0.7 0.7 0.7], ...
        'LineWidth', 1, ...
        'HandleVisibility', 'off');

    p_rmse = plot(s_rmse(i), i + offset, 'o', ...
        'MarkerSize', 10, ...
        'MarkerFaceColor', colors{sIdx(i)}, ...
        'MarkerEdgeColor', 'k', ...
        'LineWidth', 1);

    text(s_rmse(i) + 0.001, i + offset, ...
        sprintf('%.4f', s_rmse(i)), ...
        'FontSize', 9, ...
        'FontName', 'Times New Roman', ...
        'FontWeight', 'bold');

    % MAPE.
    line([0, s_mape(i)], [i - offset, i - offset], ...
        'Color', [0.8 0.8 0.8], ...
        'LineWidth', 1, ...
        'LineStyle', ':', ...
        'HandleVisibility', 'off');

    p_mape = plot(s_mape(i), i - offset, 'd', ...
        'MarkerSize', 8, ...
        'MarkerFaceColor', [0.95 0.95 0.95], ...
        'MarkerEdgeColor', colors{sIdx(i)}, ...
        'LineWidth', 1);

    text(s_mape(i) + 0.001, i - offset, ...
        sprintf('%.4f', s_mape(i)), ...
        'FontSize', 8, ...
        'Color', [0.4 0.4 0.4]);
end

set(gca, ...
    'YTick', 1:num_models, ...
    'YTickLabel', s_names, ...
    'FontSize', 12, ...
    'FontName', 'Times New Roman');

xlabel('Error metric value', 'FontSize', 14);

xlim([0, max(rmse_vec) * 1.25]);

legend([p_rmse, p_mape], {'RMSE', 'MAPE'}, ...
    'Location', 'southeast', ...
    'FontSize', 11);

box on;

ax = gca;
ax.GridLineStyle = '--';
ax.GridAlpha = 0.3;

hold off;

local_save_figure(fig_lollipop, ...
    cfg.fig_lollipop, ...
    cfg.png_lollipop, ...
    cfg.png_resolution);

%% 5) Panel H: Horizontal gradient R2 performance chart
fig_r2_gradient = figure('Color', 'w', ...
    'Position', [100 100 700 450], ...
    'Name', 'P2_Exp09_RegressionHeadR2Summary');

hold on;

fill([0.9, 1.05, 1.05, 0.9], ...
     [0.5, 0.5, num_models + 0.5, num_models + 0.5], ...
     [0.9 0.98 0.9], ...
     'EdgeColor', 'none', ...
     'FaceAlpha', 0.5);

fill([0.8, 0.9, 0.9, 0.8], ...
     [0.5, 0.5, num_models + 0.5, num_models + 0.5], ...
     [1 1 0.85], ...
     'EdgeColor', 'none', ...
     'FaceAlpha', 0.5);

text(0.95, num_models + 0.65, 'Excellent Zone', ...
    'FontSize', 10, ...
    'FontWeight', 'bold', ...
    'Color', [0.2 0.5 0.2], ...
    'HorizontalAlignment', 'center');

text(0.85, num_models + 0.65, 'Good Zone', ...
    'FontSize', 10, ...
    'FontWeight', 'bold', ...
    'Color', [0.6 0.5 0.2], ...
    'HorizontalAlignment', 'center');

w = 0.25;

for i = 1:num_models

    px = [0.7, r2_vec(i), r2_vec(i), 0.7];
    py = [i - w, i - w, i + w, i + w];

    v_colors = [ ...
        colors{i} * 0.6; ...
        colors{i}; ...
        colors{i}; ...
        colors{i} * 0.6];

    patch('Faces', 1:4, ...
          'Vertices', [px' py'], ...
          'FaceVertexCData', v_colors, ...
          'FaceColor', 'interp', ...
          'EdgeColor', 'k', ...
          'LineWidth', 1.2);

    line([r2_vec(i) r2_vec(i)], [i - w, i + w], ...
        'Color', [1 1 1], ...
        'LineWidth', 2);

    text(r2_vec(i) + 0.01, i, sprintf('%.4f', r2_vec(i)), ...
        'HorizontalAlignment', 'left', ...
        'FontSize', 11, ...
        'FontWeight', 'bold', ...
        'BackgroundColor', 'w', ...
        'EdgeColor', colors{i}, ...
        'Margin', 2, ...
        'LineWidth', 1);
end

set(gca, ...
    'YTick', 1:num_models, ...
    'YTickLabel', model_names, ...
    'FontSize', 12, ...
    'FontName', 'Times New Roman', ...
    'TickDir', 'out');

xlabel('$R^2$ Score', ...
    'Interpreter', 'latex', ...
    'FontSize', 14, ...
    'FontWeight', 'bold');

xlim([0.7, 1.08]);
ylim([0.5, num_models + 1.0]);

grid on;

ax = gca;
ax.GridLineStyle = ':';
ax.Layer = 'top';

box on;
hold off;

local_save_figure(fig_r2_gradient, ...
    cfg.fig_r2_gradient, ...
    cfg.png_r2_gradient, ...
    cfg.png_resolution);

%% 6) Save metric and prediction tables
Metrics_Table = table(model_names(:), r2_vec, rmse_vec, mape_vec, ...
    'VariableNames', {'Model', 'R2', 'RMSE', 'MAPE'});

Prediction_Table = table( ...
    pack_idx(:), ...
    pack_id(:), ...
    y_true(:), ...
    y_mlp(:), ...
    y_gpr(:), ...
    y_svm(:), ...
    y_mlp(:) - y_true(:), ...
    y_gpr(:) - y_true(:), ...
    y_svm(:) - y_true(:), ...
    'VariableNames', { ...
    'Pack_Index', ...
    'Pack_ID', ...
    'True_SOH', ...
    'Pred_MLP', ...
    'Pred_GPR', ...
    'Pred_SVM', ...
    'Error_MLP', ...
    'Error_GPR', ...
    'Error_SVM'});

writetable(Metrics_Table, cfg.metrics_csv);
writetable(Prediction_Table, cfg.pred_csv);

fprintf('\n>>> Regression-head visualization completed.\n');
fprintf('>>> Saved metrics:     %s\n', cfg.metrics_csv);
fprintf('>>> Saved predictions: %s\n', cfg.pred_csv);
fprintf('>>> Saved panel F:     %s\n', cfg.png_parity);
fprintf('>>> Saved panel G:     %s\n', cfg.png_lollipop);
fprintf('>>> Saved panel H:     %s\n', cfg.png_r2_gradient);


%% Local helper functions
function x = local_get_numeric_col(T, candidates)
% Extract a numeric column from a table using candidate column names.

vars = T.Properties.VariableNames;
col = local_find_col(vars, candidates);

if isempty(col)
    disp(vars');
    error('Required column not found. Candidate names: %s', strjoin(candidates, ', '));
end

x = T.(col);

if iscell(x) || isstring(x) || ischar(x)
    x = str2double(string(x));
end

x = double(x);
x = x(:);
end

function x = local_get_optional_numeric_col(T, candidates, default_value)
% Extract an optional numeric column. If not found, return the default value.

vars = T.Properties.VariableNames;
col = local_find_col(vars, candidates);

if isempty(col)
    x = default_value;
    return;
end

x = T.(col);

if iscell(x) || isstring(x) || ischar(x)
    x = str2double(string(x));
end

x = double(x);
x = x(:);
end

function x = local_get_optional_text_col(T, candidates, default_value)
% Extract an optional text column. If not found, return the default value.

vars = T.Properties.VariableNames;
col = local_find_col(vars, candidates);

if isempty(col)
    x = default_value;
    return;
end

x = string(T.(col));
x = x(:);
end

function col = local_find_col(vars, candidates)
% Find a column by matching normalized column names.

col = '';

vars_norm = cell(size(vars));

for i = 1:numel(vars)
    vars_norm{i} = local_normalize_name(vars{i});
end

for i = 1:numel(candidates)

    cand_norm = local_normalize_name(candidates{i});
    idx = find(strcmp(vars_norm, cand_norm), 1);

    if ~isempty(idx)
        col = vars{idx};
        return;
    end
end
end

function s = local_normalize_name(s)
% Normalize column names for robust matching.

s = char(s);
s = lower(s);
s = regexprep(s, '[^a-z0-9]', '');
end

function local_save_figure(fig_handle, fig_file, png_file, resolution)
% Save a figure as both FIG and PNG files.

out_dir = fileparts(fig_file);

if ~exist(out_dir, 'dir')
    mkdir(out_dir);
end

savefig(fig_handle, fig_file);
exportgraphics(fig_handle, png_file, 'Resolution', resolution);

fprintf('[Figure] Saved: %s\n', png_file);
end
